{
  "executive_summary": "A real-time courier bidding system built around three core primitives: WebSocket fan-out for sub-second job broadcast, Redis atomic compare-and-set for race-safe acceptance, and a timer-wheel scheduler for 15-second timeout enforcement. The design separates the hot path (bid acceptance) from the warm path (eligibility, rating lookup, notifications) to keep p99 acceptance latency under 50ms while supporting 500 concurrent bid windows with 30 couriers each.",

  "architecture": {
    "components": [
      {
        "name": "Order Ingress Service",
        "responsibility": "Receives new orders from the marketplace API, validates them, enriches with zone/geo data, and emits an OrderPlaced domain event to kick off the bidding lifecycle.",
        "boundaries": "Owns order validation and initial persistence. Does NOT own courier selection or bid state."
      },
      {
        "name": "Bid Orchestrator",
        "responsibility": "Core state machine for each bid window. On OrderPlaced: (1) queries Eligibility Service for courier pool, (2) creates a BidWindow in Redis with state OPEN + 15s TTL, (3) fans out job notifications via WebSocket Gateway, (4) registers a timeout callback. On acceptance: executes atomic claim. On timeout: triggers fallback assignment.",
        "boundaries": "Owns bid window lifecycle (OPEN → CLAIMED | TIMEOUT → ASSIGNED). Does not own courier profiles, ratings, or order fulfillment."
      },
      {
        "name": "Redis Bid Store",
        "responsibility": "Single source of truth for bid window state. Each bid window is a Redis key (bid:{orderId}) with fields: state, winnerId, expiresAt. Acceptance uses a Lua script for atomic compare-and-set: only transitions OPEN → CLAIMED. Provides the atomicity guarantee that prevents double-acceptance.",
        "boundaries": "Stateful but ephemeral — bid windows expire after claim or timeout. Not a durable store; outcomes are projected to PostgreSQL asynchronously."
      },
      {
        "name": "WebSocket Gateway",
        "responsibility": "Maintains persistent WebSocket connections to courier mobile apps. Handles connection lifecycle, heartbeats, authentication, and channel subscriptions (couriers subscribe to their zone channel). Fans out JobAvailable messages and receives AcceptBid messages from couriers.",
        "boundaries": "Transport layer only — no business logic. Routes AcceptBid to Bid Orchestrator. Horizontally scaled behind a load balancer with sticky sessions."
      },
      {
        "name": "Timeout Scheduler",
        "responsibility": "Manages 15-second deadlines for all active bid windows. Implemented as a Redis sorted set (ZSET) keyed by expiration timestamp. A polling loop (every 500ms) picks up expired windows and emits BidWindowExpired events. Guarantees at-least-once timeout firing.",
        "boundaries": "Owns only the scheduling concern. Delegates fallback assignment logic to Bid Orchestrator."
      },
      {
        "name": "Eligibility Service",
        "responsibility": "Determines which couriers are eligible for a given order based on zone, availability status, active delivery count, vehicle type, and compliance. Returns a ranked list of eligible couriers with their ratings for fallback assignment.",
        "boundaries": "Read-only query service over courier profiles. Does not mutate courier state."
      },
      {
        "name": "Assignment Projection Service",
        "responsibility": "Listens for BidClaimed and FallbackAssigned events. Writes the final assignment to PostgreSQL (durable record), updates courier availability status, and notifies the Order Service that fulfillment can begin.",
        "boundaries": "Write-behind projection. The assignment is authoritative from Redis the moment it happens; this service provides durability and downstream integration."
      },
      {
        "name": "Courier Presence Tracker",
        "responsibility": "Tracks real-time courier online/offline status and last-known location via WebSocket heartbeats. Feeds into Eligibility Service to filter out offline couriers before broadcast.",
        "boundaries": "Owns presence state (online, idle, busy). Updated by WebSocket Gateway connection events and periodic heartbeats."
      }
    ],
    "interfaces": [
      {
        "from": "Order Ingress Service",
        "to": "Bid Orchestrator",
        "contract": "OrderPlaced event: { orderId, pickupLocation, dropoffLocation, zoneId, orderType, timestamp }",
        "coupling_type": "async (event bus)"
      },
      {
        "from": "Bid Orchestrator",
        "to": "Eligibility Service",
        "contract": "GET /eligible-couriers?zoneId={z}&orderType={t} → { couriers: [{ courierId, rating, vehicleType }] }",
        "coupling_type": "sync (HTTP, <20ms within same cluster)"
      },
      {
        "from": "Bid Orchestrator",
        "to": "Redis Bid Store",
        "contract": "Lua script: CREATE_BID_WINDOW(orderId, courierIds, expiresAt) → OK; CLAIM_BID(orderId, courierId) → CLAIMED | ALREADY_CLAIMED | EXPIRED",
        "coupling_type": "sync (Redis protocol, sub-millisecond)"
      },
      {
        "from": "Bid Orchestrator",
        "to": "WebSocket Gateway",
        "contract": "Internal publish to zone channel: JobAvailable { orderId, pickup, dropoff, estimatedPay, expiresAt }; targeted push: JobClaimed { orderId, winnerId } to all couriers in window",
        "coupling_type": "async (internal pub/sub via Redis Pub/Sub)"
      },
      {
        "from": "WebSocket Gateway",
        "to": "Bid Orchestrator",
        "contract": "AcceptBid { orderId, courierId, timestamp } routed via internal queue",
        "coupling_type": "async (internal queue, but processed within milliseconds)"
      },
      {
        "from": "Timeout Scheduler",
        "to": "Bid Orchestrator",
        "contract": "BidWindowExpired { orderId, eligibleCouriers: [{ courierId, rating }] }",
        "coupling_type": "async (event/callback)"
      },
      {
        "from": "Bid Orchestrator",
        "to": "Assignment Projection Service",
        "contract": "BidClaimed { orderId, courierId, claimedAt } or FallbackAssigned { orderId, courierId, reason, assignedAt }",
        "coupling_type": "async (event bus)"
      },
      {
        "from": "WebSocket Gateway",
        "to": "Courier Presence Tracker",
        "contract": "ConnectionOpened / ConnectionClosed / Heartbeat { courierId, location, timestamp }",
        "coupling_type": "async (internal event)"
      }
    ],
    "data_flow": "1) Order Ingress emits OrderPlaced → 2) Bid Orchestrator queries Eligibility Service for ~30 eligible couriers → 3) Bid Orchestrator creates bid window in Redis (state=OPEN, TTL=15s) and registers timeout in Scheduler ZSET → 4) Bid Orchestrator publishes JobAvailable to zone channel via WebSocket Gateway → 5) Couriers see job on mobile, tap accept → 6) WebSocket Gateway routes AcceptBid to Bid Orchestrator → 7) Bid Orchestrator executes Lua CLAIM_BID script: if OPEN, atomically sets state=CLAIMED + winnerId, returns CLAIMED; if already claimed, returns ALREADY_CLAIMED → 8a) On CLAIMED: emit BidClaimed event, fan out JobClaimed to all couriers in window (losers see 'taken'), cancel timeout → 8b) On ALREADY_CLAIMED: send RejectedBid to the losing courier → 9) If no courier accepts within 15s, Timeout Scheduler fires BidWindowExpired → Bid Orchestrator selects highest-rated available courier from the eligible list, force-assigns, emits FallbackAssigned → 10) Assignment Projection Service persists to PostgreSQL and updates courier status.",
    "patterns_used": [
      {
        "pattern": "Atomic Compare-and-Set via Redis Lua Script",
        "rationale": "The core invariant — exactly one courier wins — requires an atomic read-check-write. Redis Lua scripts execute atomically (single-threaded), making them ideal for a lightweight distributed lock. No need for heavier distributed consensus for this use case since a single Redis master handles the hot path with sub-ms latency."
      },
      {
        "pattern": "Fan-out on Write (Pub/Sub + WebSocket)",
        "rationale": "With 30 couriers per zone and 500 concurrent windows, broadcasting via zone-based pub/sub channels is efficient. Couriers subscribe to their zone channel. Total message throughput: 500 broadcasts × 30 recipients = 15,000 pushes, well within Redis Pub/Sub and WebSocket gateway capacity."
      },
      {
        "pattern": "Timer Wheel / Sorted Set Scheduler",
        "rationale": "500 concurrent 15-second timeouts need reliable, efficient scheduling. A Redis ZSET keyed by expiration timestamp allows O(log N) insertion and O(1) range queries for expired entries. Polling at 500ms granularity provides sub-second timeout accuracy without per-window OS timers."
      },
      {
        "pattern": "Event-Driven State Machine",
        "rationale": "The bid window has a clear lifecycle (OPEN → CLAIMED | EXPIRED → ASSIGNED). Modeling this as an explicit state machine prevents illegal transitions, makes the system auditable, and decouples the hot path (acceptance) from downstream effects (assignment persistence, notifications)."
      },
      {
        "pattern": "CQRS — Command/Query Separation for Assignment",
        "rationale": "The authoritative bid state lives in Redis for speed. A separate projection writes the durable assignment record to PostgreSQL asynchronously. This separates the latency-critical write (claim) from the durability-critical write (persist), optimizing each independently."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Bidding",
        "classification": "core",
        "aggregates": [
          {
            "name": "BidWindow",
            "root": "BidWindow",
            "invariants": [
              "A BidWindow in OPEN state can transition to CLAIMED (by exactly one courier) or EXPIRED (by timeout)",
              "Once CLAIMED or EXPIRED, no further acceptance is possible",
              "A BidWindow must have at least one eligible courier",
              "ExpiresAt must be exactly 15 seconds after creation"
            ],
            "entities": ["BidWindow"],
            "value_objects": ["BidWindowId", "AcceptanceAttempt", "BidOutcome", "ExpirationPolicy"]
          }
        ]
      },
      {
        "name": "Courier Availability",
        "classification": "supporting",
        "aggregates": [
          {
            "name": "CourierPresence",
            "root": "CourierPresence",
            "invariants": [
              "A courier is available only if online, not at max active deliveries, and in a valid zone",
              "Presence status must reflect actual WebSocket connection state"
            ],
            "entities": ["CourierPresence"],
            "value_objects": ["PresenceStatus", "ZoneAssignment", "LastKnownLocation"]
          }
        ]
      },
      {
        "name": "Order Management",
        "classification": "supporting",
        "aggregates": [
          {
            "name": "Order",
            "root": "Order",
            "invariants": [
              "An order transitions to IN_BIDDING only once",
              "An order must have a confirmed assignment before moving to FULFILLMENT"
            ],
            "entities": ["Order"],
            "value_objects": ["OrderId", "PickupLocation", "DropoffLocation", "ZoneId"]
          }
        ]
      },
      {
        "name": "Courier Profiles & Ratings",
        "classification": "generic",
        "aggregates": [
          {
            "name": "CourierProfile",
            "root": "CourierProfile",
            "invariants": ["Rating is a derived aggregate from completed deliveries"],
            "entities": ["CourierProfile"],
            "value_objects": ["Rating", "VehicleType", "ComplianceStatus"]
          }
        ]
      }
    ],
    "context_map": [
      {
        "upstream": "Order Management",
        "downstream": "Bidding",
        "relationship": "Customer-Supplier — Order Management publishes OrderPlaced; Bidding consumes it. Bidding defines what order data it needs (Published Language). Order Management accommodates."
      },
      {
        "upstream": "Courier Profiles & Ratings",
        "downstream": "Bidding",
        "relationship": "Conformist — Bidding reads courier ratings as-is for fallback assignment. No translation needed; the rating model is simple enough."
      },
      {
        "upstream": "Courier Availability",
        "downstream": "Bidding",
        "relationship": "Customer-Supplier — Bidding queries availability to build the eligible courier pool. Availability exposes an Open Host Service (query API)."
      },
      {
        "upstream": "Bidding",
        "downstream": "Order Management",
        "relationship": "Customer-Supplier — Bidding emits BidClaimed/FallbackAssigned. Order Management consumes to advance order lifecycle."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Single Redis master for bid state (not a Redis Cluster for the hot path)",
      "gains": "True atomicity via Lua scripts without cross-slot complexity. Sub-millisecond latency. Simpler operational model. 500 concurrent windows × ~1KB each = negligible memory.",
      "sacrifices": "Single point of failure for the bidding hot path. If Redis master dies, active bid windows are lost.",
      "alternatives_considered": [
        "Redis Cluster with hash tags — adds complexity for cross-key atomicity, unnecessary at 500 concurrent windows",
        "PostgreSQL advisory locks — higher latency (5-20ms vs <1ms), adequate but leaves performance on the table",
        "DynamoDB conditional writes — viable but adds external dependency and ~10ms latency per write"
      ]
    },
    {
      "decision": "Polling-based timeout scheduler (ZSET + 500ms poll) instead of per-window delayed messages",
      "gains": "Single polling loop manages all 500 timeouts. No message broker dependency. Easy to inspect and debug. Graceful on scheduler restart (ZSET is persistent).",
      "sacrifices": "Up to 500ms jitter on timeout firing. A 15-second window might actually be 15.0–15.5 seconds.",
      "alternatives_considered": [
        "Per-window setTimeout / delayed queue message — more precise but 500 concurrent timers adds operational complexity",
        "Redis keyspace notifications with TTL expiry — unreliable (notifications are best-effort, not guaranteed delivery)"
      ]
    },
    {
      "decision": "Redis Pub/Sub for WebSocket fan-out (not a dedicated message broker)",
      "gains": "Already have Redis in the stack. Sub-millisecond publish latency. Zone-based channels map naturally to Pub/Sub topics. At 15,000 messages per broadcast cycle, well within Redis capacity.",
      "sacrifices": "Redis Pub/Sub is fire-and-forget — if a WebSocket Gateway node is down during publish, those couriers miss the notification. No replay.",
      "alternatives_considered": [
        "Kafka/NATS for guaranteed delivery — overkill for ephemeral 15-second notifications; a missed notification just means the courier doesn't bid",
        "Direct HTTP push to each courier — 30 sequential HTTP calls adds unacceptable latency"
      ]
    },
    {
      "decision": "Async projection to PostgreSQL (eventual consistency for durable assignment record)",
      "gains": "Hot path stays entirely in Redis. Assignment is confirmed to the courier in <50ms. PostgreSQL write can tolerate 100-500ms delay without user impact.",
      "sacrifices": "Brief window where Redis has the assignment but PostgreSQL doesn't. If Redis and the projection service both fail simultaneously, the assignment could be lost.",
      "alternatives_considered": [
        "Synchronous dual-write to Redis + PostgreSQL — doubles hot-path latency, introduces distributed transaction complexity",
        "PostgreSQL only (no Redis) — simpler but acceptance latency jumps to 5-20ms under contention, harder to guarantee atomicity at scale"
      ]
    }
  ],

  "flexibility_points": [
    {
      "area": "Eligibility criteria",
      "evolution_path": "The Eligibility Service is a separate query boundary. Adding new eligibility rules (e.g., courier preferences, dynamic pricing tiers, blacklists) requires no changes to the Bid Orchestrator. Plug in new eligibility strategies behind the same interface."
    },
    {
      "area": "Bid window duration",
      "evolution_path": "The 15-second window is a configuration parameter on BidWindow creation, not hardcoded. Can evolve to dynamic timeouts (e.g., shorter windows during peak hours, longer in low-density zones) by changing the ExpirationPolicy value object."
    },
    {
      "area": "Fallback assignment strategy",
      "evolution_path": "Currently highest-rated courier. The strategy is encapsulated behind a FallbackAssignmentStrategy interface. Can swap to round-robin, proximity-based, or auction-style (couriers bid a price) without touching the orchestrator."
    },
    {
      "area": "WebSocket transport",
      "evolution_path": "The WebSocket Gateway is a pure transport layer. Can be replaced with SSE, long-polling, or a push notification service (e.g., Firebase Cloud Messaging for background mobile state) without affecting bid logic."
    },
    {
      "area": "Multi-region expansion",
      "evolution_path": "Bid windows are zone-scoped and self-contained. Can partition Redis by region (one Redis per region) and scale the WebSocket Gateway fleet per region independently."
    }
  ],

  "rigidity_points": [
    {
      "area": "Redis as the atomic arbiter",
      "reason": "The entire atomicity guarantee depends on Redis Lua script execution. Replacing Redis requires finding another single-writer atomic primitive. This is intentional — the acceptance hot path must be opinionated about its consistency mechanism."
    },
    {
      "area": "Single-winner model",
      "reason": "The state machine enforces exactly one winner per bid window. If the business later wants multi-courier pickup or split assignments, the BidWindow aggregate and Lua script need a fundamental redesign."
    },
    {
      "area": "Synchronous eligibility query",
      "reason": "The Bid Orchestrator makes a synchronous call to Eligibility Service before broadcasting. If eligibility computation becomes slow (>100ms), it blocks bid window creation. Could be mitigated with a pre-computed eligibility cache, but that's a future optimization."
    }
  ],

  "risks": [
    {
      "risk": "Redis master failure during active bid windows causes loss of in-flight bids",
      "severity": "high",
      "mitigation": "Deploy Redis with Sentinel for automatic failover (<5s). Accept that bid windows active during failover are lost — the Timeout Scheduler will re-fire for any window that didn't complete, and the Order Ingress can re-emit OrderPlaced for orders stuck in bidding. Add a reconciliation job that detects orders in IN_BIDDING state for >30 seconds and re-triggers."
    },
    {
      "risk": "WebSocket Gateway node failure causes a subset of couriers to miss job notifications",
      "severity": "medium",
      "mitigation": "Run multiple gateway nodes with automatic reconnection on the mobile client (exponential backoff, <2s reconnect). Couriers who reconnect within the 15-second window can still see and accept active jobs via a 'pull' endpoint that lists open bid windows in their zone."
    },
    {
      "risk": "Clock skew between Bid Orchestrator and Timeout Scheduler causes premature or late timeout",
      "severity": "low",
      "mitigation": "Both use the same Redis instance's TIME command as the authoritative clock. No dependency on host system clocks for timeout logic."
    },
    {
      "risk": "Courier app latency causes bids to arrive after the window closes, frustrating couriers",
      "severity": "medium",
      "mitigation": "Include expiresAt in the JobAvailable message so the mobile app can show a countdown timer and disable the accept button client-side before the server-side window closes. Add a 500ms grace period server-side before transitioning to EXPIRED."
    },
    {
      "risk": "Thundering herd: 500 orders simultaneously create 500 eligibility queries and 15,000 WebSocket pushes",
      "severity": "medium",
      "mitigation": "The eligibility query is a read-only lookup against cached courier data (Redis or in-memory). WebSocket fan-out is naturally batched by zone. Redis Pub/Sub handles this throughput easily. If needed, add a short random jitter (0-200ms) to bid window creation to smooth spikes."
    },
    {
      "risk": "Projection lag: PostgreSQL assignment record is delayed, causing downstream systems (dispatch, tracking) to see stale state",
      "severity": "medium",
      "mitigation": "Downstream systems that need real-time assignment status should read from Redis (source of truth during the bid lifecycle). PostgreSQL is the system of record for completed assignments only. Add monitoring on projection lag; alert if >2 seconds."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Implement in three phases. Phase 1 (MVP): Bid Orchestrator + Redis Lua scripts + WebSocket Gateway + Timeout Scheduler. This delivers the core invariant (atomic single-winner acceptance) and the real-time courier experience. Phase 2: Eligibility Service extraction, Courier Presence Tracker, fallback assignment strategy. Phase 3: Assignment Projection to PostgreSQL, monitoring dashboards, reconciliation jobs. Start with a single Redis instance; add Sentinel in Phase 2. Use Node.js or Go for the WebSocket Gateway (high concurrency, low memory per connection). Use any language with good Redis client support for the Bid Orchestrator.",
    "files_to_create_or_modify": [
      "services/bid-orchestrator/src/bid-window.ts — BidWindow state machine (OPEN → CLAIMED | EXPIRED → ASSIGNED)",
      "services/bid-orchestrator/src/redis/claim-bid.lua — Atomic Lua script: if state==OPEN then set state=CLAIMED, winnerId=ARGV[1], return 'CLAIMED' else return current state end",
      "services/bid-orchestrator/src/redis/create-bid-window.lua — Create bid window hash with state, courierIds, expiresAt; add to timeout ZSET",
      "services/bid-orchestrator/src/timeout-scheduler.ts — ZSET polling loop, fires BidWindowExpired events",
      "services/bid-orchestrator/src/fallback-assigner.ts — Strategy pattern for fallback assignment (default: highest-rated)",
      "services/ws-gateway/src/server.ts — WebSocket server with zone-based channel subscriptions",
      "services/ws-gateway/src/redis-subscriber.ts — Subscribes to Redis Pub/Sub zone channels, fans out to connected couriers",
      "services/eligibility/src/eligible-couriers.ts — Query handler: filters by zone, availability, vehicle type; returns ranked list",
      "services/assignment-projection/src/projector.ts — Event consumer: writes BidClaimed/FallbackAssigned to PostgreSQL",
      "infrastructure/redis/bid-schema.md — Documentation of Redis key structure: bid:{orderId} hash, timeout:zset sorted set"
    ],
    "patterns_to_follow": "Use explicit state machines (no implicit boolean flags). Lua scripts for all Redis write operations touching bid state. Event-driven integration between services (no synchronous cross-service writes). Strategy pattern for fallback assignment. Repository pattern for bid window persistence (abstracts Redis behind a clean interface for testability).",
    "pitfalls_to_avoid": [
      "DO NOT use Redis WATCH/MULTI for acceptance — it retries on contention and is not truly atomic. Use Lua scripts.",
      "DO NOT rely on Redis key expiration (TTL) for timeout — keyspace notifications are best-effort and can be missed. Use explicit ZSET-based scheduling.",
      "DO NOT fan out job notifications synchronously (one HTTP call per courier). Use Pub/Sub channels.",
      "DO NOT store bid window state in PostgreSQL on the hot path — the latency budget for acceptance is <50ms.",
      "DO NOT allow the mobile app to determine acceptance order by timestamp — the server's Lua script execution order is the single source of truth.",
      "DO NOT skip the reconciliation job — in any distributed system, some bid windows will get stuck. A periodic sweep (every 30s) that re-triggers stuck orders is essential."
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 88,
    "high_confidence_areas": [
      "Atomic acceptance via Redis Lua script — well-proven pattern for single-winner race conditions",
      "WebSocket fan-out with Pub/Sub — standard architecture for real-time notifications at this scale",
      "State machine modeling for bid window lifecycle — clean, auditable, prevents illegal transitions",
      "Scale viability: 500 concurrent windows × 30 couriers is well within single-Redis and WebSocket gateway capacity"
    ],
    "low_confidence_areas": [
      "Redis failover behavior under active bid load — need to validate Sentinel promotion latency with realistic traffic",
      "Mobile app network latency distribution — if a significant portion of couriers are on slow connections, the 15-second window may feel shorter than intended",
      "Exact projection lag characteristics — depends on event bus choice and PostgreSQL write throughput under load"
    ],
    "assumptions": [
      "500 concurrent bid windows is a peak, not a sustained floor — sustained 500 would still work but warrants load testing",
      "Courier mobile apps maintain persistent WebSocket connections (standard for delivery apps)",
      "30 couriers per zone is an average — spikes to 100+ in dense zones are handled by the same architecture without changes",
      "The marketplace has a single geographic region initially — multi-region would require Redis-per-region partitioning",
      "Fallback assignment to highest-rated courier is a synchronous decision (no second bidding round)"
    ]
  }
}

